#include<bits/stdc++.h>
using namespace std;
typedef unsigned long long ull;
struct Msg
{
    ull sumx,sumy,sumxy,sums;
    Msg():sumx(0),sumy(0),sumxy(0),sums(0){}
    Msg(ull a,ull b,ull c,ull d):sumx(a),sumy(b),sumxy(c),sums(d){}
    Msg operator+(const Msg&b)const
    {
        return Msg(sumx+b.sumx,sumy+b.sumy,sumxy+b.sumxy,sums+b.sums);
    }
}msg[600010];
struct tag
{
    ull addx,addy,addxy,addc,setx,sety;
    tag():addx(0),addy(0),addxy(0),addc(0),setx(0),sety(0){}
    tag(ull a,ull b,ull c,ull d,ull e,ull f):addx(a),addy(b),addxy(c),addc(d),setx(e),sety(f){}
    operator bool()const
    {
        return addx||addy||addxy||addc||setx||sety;
    }
    tag operator*(const tag&b)const
    {
        ull ax=b.addx,ay=b.addy,axy=b.addxy,ac=b.addc;
        ull sx=b.setx,sy=b.sety;
        if(sx)
        {
            ac+=addx*sx;
            if(sy)
            {
                ac+=addxy*sx*sy;
            }
            else
            {
                ay+=addxy*sx;
            }
        }
        else
        {
            ax+=addx;
            if(sy)
            {
                ax+=addxy*sy;
            }
            else
            {
                axy+=addxy;
            }
        }
        if(sy)
        {
            ac+=addy*sy;
        }
        else
        {
            ay+=addy;
        }
        ac+=addc;
        if(setx)
        {
            sx=setx;
        }
        if(sety)
        {
            sy=sety;
        }
        return tag(ax,ay,axy,ac,sx,sy);
    }
    Msg push(Msg y,ull len)
    {
        Msg ans;
        ans.sumx=(setx?setx*len:y.sumx);
        ans.sumy=(sety?sety*len:y.sumy);
        if(setx)
        {
            ans.sumxy=(sety?setx*sety*len:setx*y.sumy);
        }
        else
        {
            ans.sumxy=(sety?sety*y.sumx:y.sumxy);
        }
        ans.sums=y.sums+y.sumx*addx+y.sumy*addy+y.sumxy*addxy+addc*len;
        return ans;
    }
}tg[600010];
void pushup(int x,int l,int r)
{
    msg[x]=tg[x].push(msg[x<<1]+msg[x<<1|1],r-l+1);
}
void push(int x,int l,int r,tag t)
{
    tg[x]=t*tg[x];
    msg[x]=t.push(msg[x],r-l+1);
}
void pushdown(int x,int l,int r)
{
    if(tg[x])
    {
        int mid=(l+r)>>1;
        push(x<<1,l,mid,tg[x]);
        push(x<<1|1,mid+1,r,tg[x]);
        tg[x]=tag();
    }
}
void update(int x,int l,int r,int u,int v,tag t)
{
    if(u<=l&&r<=v)
    {
        push(x,l,r,t);
        return;
    }
    pushdown(x,l,r);
    int mid=(l+r)>>1;
    if(u<=mid)
    {
        update(x<<1,l,mid,u,v,t);
    }
    if(v>mid)
    {
        update(x<<1|1,mid+1,r,u,v,t);
    }
    pushup(x,l,r);
}
ull query(int x,int l,int r,int u,int v)
{
    if(u<=l&&r<=v)
    {
        return msg[x].sums;
    }
    pushdown(x,l,r);
    int mid=(l+r)>>1;
    ull ans=0;
    if(u<=mid)
    {
        ans+=query(x<<1,l,mid,u,v);
    }
    if(v>mid)
    {
        ans+=query(x<<1|1,mid+1,r,u,v);
    }
    return ans;
}
struct QUERY
{
    int l,r,id;
    bool operator<(const QUERY&b)const
    {
        return r<b.r;
    }
}q[600010];
int n,m,a[600010],b[600010];
int sa[600010],sb[600010];
ull ans[600010];
int main()
{
    scanf("%*d%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&b[i]);
    }
    scanf("%d",&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&q[i].l,&q[i].r);
        q[i].id=i;
    }
    sort(q+1,q+1+m);
    int la=0,lb=0;
    for(int i=1,j=1;i<=n;i++)
    {
        while(la&&a[sa[la]]<a[i])
        {
            la--;
        }
        while(lb&&b[sb[lb]]<b[i])
        {
            lb--;
        }
        update(1,1,n,sa[la]+1,i,tag(0,0,0,0,a[i],0));
        update(1,1,n,sb[lb]+1,i,tag(0,0,0,0,0,b[i]));
        update(1,1,n,1,i,tag(0,0,1,0,0,0));
        sa[++la]=i;
        sb[++lb]=i;
        for(;j<=m&&q[j].r==i;j++)
        {
            ans[q[j].id]=query(1,1,n,q[j].l,q[j].r);
        }
    }
    for(int i=1;i<=m;i++)
    {
        printf("%llu\n",ans[i]);
    }
    return 0;
}
